/* Dashboard Minimal — Page Layout */

@import url('https://fonts.googleapis.com/css2?family=Instrument+Sans:wght@400;500;600;700&display=swap');

#page-dashboard-minimal {
    width: 1920px;
    height: 1080px;
    background: #fcfcfb;
    font-family: 'Instrument Sans', -apple-system, sans-serif;
    color: #1d1d1f;
    -webkit-font-smoothing: antialiased;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

events.beforeLoad:
/**
 * Page before_load — 이벤트 핸들러 등록
 *
 * 컴포넌트 register 이전에 실행된다.
 * Mixin 메서드에 네임스페이스로 직접 접근한다.
 */
const { onEventBusHandlers } = Wkit;

this.pageEventBusHandlers = {

    // Sidebar 메뉴 클릭
    '@menuItemClicked': ({ event, targetInstance }) => {
        const item = event.target.closest(targetInstance.statefulList.cssSelectors.menuid);
        const menuId = item?.getAttribute('data-menuid');
        console.log('[Page] Menu clicked:', menuId);
    },

    // EventBrowser 항목 클릭 → 팝업 표시
    '@eventItemClicked': ({ event, targetInstance }) => {
        const item = event.target.closest(targetInstance.listRender.cssSelectors.item);
        if (!item) return;

        targetInstance.shadowPopup.show();

        if (targetInstance._popupScope && targetInstance._popupScope.listRender) {
            const data = [
                { label: 'Time',    value: item.querySelector(targetInstance.listRender.cssSelectors.time)?.textContent },
                { label: 'Level',   value: item.querySelector(targetInstance.listRender.cssSelectors.level)?.textContent },
                { label: 'Message', value: item.querySelector(targetInstance.listRender.cssSelectors.message)?.textContent },
                { label: 'Source',  value: item.querySelector(targetInstance.listRender.cssSelectors.source)?.textContent }
            ];
            targetInstance._popupScope.listRender.renderData({ response: data });
        }
    },

    // EventBrowser 팝업 닫기
    '@eventPopupClose': ({ targetInstance }) => {
        targetInstance.shadowPopup.hide();
    }
};

onEventBusHandlers(this.pageEventBusHandlers);

events.loaded:
/**
 * Page loaded — 데이터 발행 및 갱신 관리
 *
 * 모든 컴포넌트 register 이후에 실행된다.
 */
const { registerMapping, fetchAndPublish } = GlobalDataPublisher;
const { each, go } = fx;

// ======================
// DATA MAPPINGS
// ======================

this.pageDataMappings = [
    {
        topic: 'dashboard_headerInfo',
        datasetInfo: {
            datasetName: 'dashboard_headerInfo',
            param: { baseUrl: '10.23.128.125:4010' }
        }
    },
    {
        topic: 'dashboard_menuItems',
        datasetInfo: {
            datasetName: 'dashboard_menuItems',
            param: { baseUrl: '10.23.128.125:4010' }
        }
    },
    {
        topic: 'dashboard_lineChart',
        datasetInfo: {
            datasetName: 'dashboard_lineChart',
            param: { baseUrl: '10.23.128.125:4010' }
        },
        refreshInterval: 30000
    },
    {
        topic: 'dashboard_barChart',
        datasetInfo: {
            datasetName: 'dashboard_barChart',
            param: { baseUrl: '10.23.128.125:4010' }
        },
        refreshInterval: 30000
    },
    {
        topic: 'dashboard_pieChart',
        datasetInfo: {
            datasetName: 'dashboard_pieChart',
            param: { baseUrl: '10.23.128.125:4010' }
        },
        refreshInterval: 30000
    },
    {
        topic: 'dashboard_gauge',
        datasetInfo: {
            datasetName: 'dashboard_gauge',
            param: { baseUrl: '10.23.128.125:4010' }
        },
        refreshInterval: 10000
    },
    {
        topic: 'dashboard_tableData',
        datasetInfo: {
            datasetName: 'dashboard_tableData',
            param: { baseUrl: '10.23.128.125:4010' }
        },
        refreshInterval: 30000
    },
    {
        topic: 'dashboard_events',
        datasetInfo: {
            datasetName: 'dashboard_events',
            param: { baseUrl: '10.23.128.125:4010' }
        },
        refreshInterval: 15000
    }
];

// ======================
// REGISTER + INITIAL FETCH
// ======================

this.pageParams = {};

go(
    this.pageDataMappings,
    each(registerMapping),
    each(({ topic }) => this.pageParams[topic] = {}),
    each(({ topic }) =>
        fetchAndPublish(topic, this)
            .catch(err => console.error(`[Page] ${topic} fetch failed:`, err))
    )
);

// ======================
// INTERVAL MANAGEMENT (setTimeout 체이닝)
// ======================

this.pageIntervals = {};

this.startAllIntervals = () => {
    go(
        this.pageDataMappings,
        each(({ topic, refreshInterval }) => {
            if (!refreshInterval) return;

            const state = { _stopped: false, _timerId: null };
            this.pageIntervals[topic] = state;

            const scheduleNext = () => {
                if (state._stopped) return;
                state._timerId = setTimeout(() => {
                    fetchAndPublish(topic, this, this.pageParams[topic] || {})
                        .catch(err => console.error(`[Page] ${topic} refresh failed:`, err))
                        .finally(scheduleNext);
                }, refreshInterval);
            };
            scheduleNext();
        })
    );
};

this.stopAllIntervals = () => {
    go(
        Object.entries(this.pageIntervals),
        each(([_, state]) => {
            state._stopped = true;
            clearTimeout(state._timerId);
        })
    );
};

this.startAllIntervals();

events.beforeUnLoad:
/**
 * Page before_unload — 모든 리소스 정리
 */
const { unregisterMapping } = GlobalDataPublisher;
const { offEventBusHandlers } = Wkit;
const { each, go } = fx;

// ======================
// INTERVAL CLEANUP
// ======================

if (this.stopAllIntervals) {
    this.stopAllIntervals();
}
this.pageIntervals = null;

// ======================
// EVENT BUS CLEANUP
// ======================

offEventBusHandlers(this.pageEventBusHandlers);
this.pageEventBusHandlers = null;

// ======================
// DATA PUBLISHER CLEANUP
// ======================

go(
    this.pageDataMappings,
    each(({ topic }) => unregisterMapping(topic))
);

this.pageDataMappings = null;
this.pageParams = null;

